<script setup lang="ts">
import { computed, ref } from 'vue'
import { Delete, Edit, Location, MoreFilled, Picture, Plus, ShoppingBag, TopRight, User } from '@element-plus/icons-vue'
import type { ShoppingItem, ShoppingPriority, ShoppingStatus, ShoppingType, Trip } from '../types'

const props = defineProps<{ trip: Trip; items: ShoppingItem[]; canEditTrip: boolean; memberName: (memberId: string) => string }>()
const emit = defineEmits<{ add: []; edit: [item: ShoppingItem]; remove: [item: ShoppingItem]; status: [item: ShoppingItem, status: ShoppingStatus]; convert: [item: ShoppingItem] }>()

const statusFilter = ref<'all' | ShoppingStatus>('all')
const typeFilter = ref<'all' | ShoppingType>('all')
const categoryFilter = ref('all')
const assigneeFilter = ref('all')
const storeFilter = ref('all')
const storeMode = ref(false)
const groupByStore = ref(true)

const statusLabels: Record<ShoppingStatus, string> = { wishlist: '想買', planned: '已規劃', purchased: '已購買', unavailable: '缺貨', cancelled: '已取消' }
const typeLabels: Record<ShoppingType, string> = { personal: '個人購物', proxy: '代購', shared: '共同採買', gift: '伴手禮' }
const priorityLabels: Record<ShoppingPriority, string> = { high: '高優先', medium: '一般', low: '低優先' }
const categories = computed(() => [...new Set(props.items.map((item) => item.category).filter(Boolean))].sort((a, b) => a.localeCompare(b, 'zh-Hant')))
const stores = computed(() => [...new Set(props.items.map((item) => item.storeName?.trim()).filter((store): store is string => Boolean(store)))].sort((a, b) => a.localeCompare(b, 'zh-Hant')))
const sortedItems = computed(() => [...props.items].sort((a, b) => {
  const statusOrder: Record<ShoppingStatus, number> = { planned: 0, wishlist: 1, unavailable: 2, cancelled: 3, purchased: 4 }
  const priorityOrder: Record<ShoppingPriority, number> = { high: 0, medium: 1, low: 2 }
  return statusOrder[a.status] - statusOrder[b.status] || priorityOrder[a.priority] - priorityOrder[b.priority] || (a.plannedDate || '9999-12-31').localeCompare(b.plannedDate || '9999-12-31') || b.createdAt - a.createdAt
}))
const visibleItems = computed(() => sortedItems.value.filter((item) => (statusFilter.value === 'all' || item.status === statusFilter.value) && (typeFilter.value === 'all' || item.shoppingType === typeFilter.value) && (categoryFilter.value === 'all' || item.category === categoryFilter.value) && (assigneeFilter.value === 'all' || (assigneeFilter.value === 'unassigned' ? !item.assignedTo : item.assignedTo === assigneeFilter.value)) && (storeFilter.value === 'all' || item.storeName === storeFilter.value)))
const displayGroups = computed(() => {
  if (!groupByStore.value) return [{ name: '', items: visibleItems.value }]
  const groups = new Map<string, ShoppingItem[]>()
  visibleItems.value.forEach((item) => { const name = item.storeName?.trim() || '尚未指定店家'; (groups.get(name) || groups.set(name, []).get(name)!).push(item) })
  return [...groups.entries()].map(([name, items]) => ({ name, items }))
})
const purchasedCount = computed(() => props.items.filter((item) => item.status === 'purchased').length)
const outstandingCount = computed(() => props.items.filter((item) => item.status === 'wishlist' || item.status === 'planned').length)
const estimateTotal = computed(() => props.items.filter((item) => item.status !== 'cancelled').reduce((sum, item) => sum + (Number(item.estimatedTotalPrice) || (Number(item.estimatedUnitPrice) || 0) * item.quantity), 0))
const actualTotal = computed(() => props.items.filter((item) => item.status === 'purchased').reduce((sum, item) => sum + (Number(item.actualTotalPrice) || (Number(item.actualUnitPrice) || 0) * item.quantity || Number(item.estimatedTotalPrice) || 0), 0))
function amount(item: ShoppingItem, actual = false) { const total = actual ? Number(item.actualTotalPrice) || (Number(item.actualUnitPrice) || 0) * item.quantity : Number(item.estimatedTotalPrice) || (Number(item.estimatedUnitPrice) || 0) * item.quantity; return total > 0 ? `${item.currency} ${total.toLocaleString()}` : '' }
function mapsUrl(item: ShoppingItem) { if (item.mapUrl) return item.mapUrl; const query = item.address || item.location || [item.storeName, item.storeBranch].filter(Boolean).join(' '); return query ? `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(query)}` : '' }
function toggleStoreMode() { storeMode.value = !storeMode.value; if (storeMode.value && storeFilter.value === 'all' && stores.value[0]) storeFilter.value = stores.value[0]; if (!storeMode.value) storeFilter.value = 'all' }
</script>

<template>
  <section id="shopping" class="trip-detail-card shopping-panel">
    <div class="detail-card-heading"><div><p class="section-kicker">SHOPPING</p><h2>購物清單</h2><p>集中記下想買、代購與旅伴共同採買的商品。</p></div><div class="shopping-heading-actions"><el-button class="shopping-store-mode" :class="{ 'is-active': storeMode }" @click="toggleStoreMode"><el-icon><Location /></el-icon>{{ storeMode ? '離開到店模式' : '到店模式' }}</el-button><el-button v-if="canEditTrip" class="shopping-add-button" @click="emit('add')"><el-icon><Plus /></el-icon>新增商品</el-button><span v-else class="readonly-chip">唯讀</span></div></div>

    <div class="shopping-summary"><div><span>商品總數</span><strong>{{ items.length }}</strong></div><div><span>尚待購買</span><strong>{{ outstandingCount }}</strong></div><div><span>已購買</span><strong>{{ purchasedCount }}</strong></div><div><span>預估總額</span><strong>{{ trip.currency }} {{ estimateTotal.toLocaleString() }}</strong></div><div><span>實際已花</span><strong>{{ trip.currency }} {{ actualTotal.toLocaleString() }}</strong></div></div>

    <div class="shopping-filters"><el-select v-model="statusFilter" aria-label="依狀態篩選"><el-option label="全部狀態" value="all" /><el-option v-for="(label, status) in statusLabels" :key="status" :label="label" :value="status" /></el-select><el-select v-model="typeFilter" aria-label="依購物類型篩選"><el-option label="全部類型" value="all" /><el-option v-for="(label, type) in typeLabels" :key="type" :label="label" :value="type" /></el-select><el-select v-model="categoryFilter" aria-label="依分類篩選"><el-option label="全部分類" value="all" /><el-option v-for="category in categories" :key="category" :label="category" :value="category" /></el-select><el-select v-model="assigneeFilter" aria-label="依負責人篩選"><el-option label="全部負責人" value="all" /><el-option label="尚未分派" value="unassigned" /><el-option v-for="member in trip.members" :key="member.id" :label="member.name" :value="member.id" /></el-select><el-select v-if="storeMode || stores.length" v-model="storeFilter" aria-label="依店家篩選"><el-option label="全部店家" value="all" /><el-option v-for="store in stores" :key="store" :label="store" :value="store" /></el-select><el-button class="shopping-group-button" text @click="groupByStore = !groupByStore">{{ groupByStore ? '依店家顯示中' : '依清單顯示中' }}</el-button></div>

    <div v-if="visibleItems.length" class="shopping-groups" :class="{ 'is-store-mode': storeMode }"><section v-for="group in displayGroups" :key="group.name || 'all'" class="shopping-store-group"><div v-if="groupByStore" class="shopping-store-heading"><div><el-icon><Location /></el-icon><strong>{{ group.name }}</strong></div><span>{{ group.items.filter((item) => item.status !== 'purchased').length }} 件待購買</span></div><div class="shopping-list"><article v-for="item in group.items" :key="item.id" class="shopping-row" :class="[`is-${item.status}`, `is-${item.priority}`]"><img v-if="item.imageUrl" :src="item.imageUrl" :alt="`${item.name} 商品圖片`" class="shopping-image" /><span v-else class="shopping-image shopping-image-placeholder"><el-icon><ShoppingBag /></el-icon></span><div class="shopping-copy"><div class="shopping-title"><strong>{{ item.name }}</strong><span :class="['shopping-status-badge', `is-${item.status}`]">{{ statusLabels[item.status] }}</span><span :class="['shopping-priority-badge', `is-${item.priority}`]">{{ priorityLabels[item.priority] }}</span></div><p class="shopping-tags"><span>{{ typeLabels[item.shoppingType] }}</span><span>{{ item.category }}</span><span v-if="item.quantity > 1">{{ item.quantity }} {{ item.unit || '件' }}</span></p><p v-if="item.storeName || item.assignedTo || item.requestedBy || item.giftRecipient" class="shopping-meta"><span v-if="item.storeName"><el-icon><Location /></el-icon>{{ item.storeName }}{{ item.storeBranch ? `・${item.storeBranch}` : '' }}</span><span v-if="item.assignedTo"><el-icon><User /></el-icon>{{ memberName(item.assignedTo) }} 負責</span><span v-if="item.requestedBy">委託：{{ item.requestedBy }}</span><span v-if="item.giftRecipient">送給：{{ item.giftRecipient }}</span></p><p v-if="item.note" class="shopping-note">{{ item.note }}</p></div><div class="shopping-price"><strong v-if="amount(item, item.status === 'purchased')">{{ amount(item, item.status === 'purchased') }}</strong><span v-if="amount(item, item.status === 'purchased') && amount(item, false) && item.status === 'purchased'">預估 {{ amount(item) }}</span><span v-else-if="amount(item)">預估</span></div><div class="shopping-tools"><el-tooltip v-if="mapsUrl(item)" content="在 Google Maps 開啟店家" placement="top"><a class="shopping-tool-button" :href="mapsUrl(item)" target="_blank" rel="noopener noreferrer" aria-label="在 Google Maps 開啟店家"><el-icon><TopRight /></el-icon></a></el-tooltip><el-tooltip v-if="canEditTrip && item.status !== 'purchased' && item.status !== 'cancelled'" content="標記為已購買" placement="top"><el-button class="shopping-tool-button is-purchase" text circle :aria-label="`標記 ${item.name} 為已購買`" @click="emit('status', item, 'purchased')">✓</el-button></el-tooltip><el-dropdown v-if="canEditTrip" trigger="click" @command="(status: ShoppingStatus) => emit('status', item, status)"><el-button class="shopping-tool-button" text circle aria-label="變更商品狀態"><el-icon><MoreFilled /></el-icon></el-button><template #dropdown><el-dropdown-menu><el-dropdown-item v-for="(label, status) in statusLabels" :key="status" :command="status" :disabled="item.status === status">{{ label }}</el-dropdown-item></el-dropdown-menu></template></el-dropdown><el-tooltip v-if="canEditTrip && item.status === 'purchased' && !item.expenseId" content="建立旅行開銷" placement="top"><el-button class="shopping-tool-button is-expense" text circle aria-label="建立旅行開銷" @click="emit('convert', item)">¥</el-button></el-tooltip><el-tooltip v-if="canEditTrip" content="編輯商品" placement="top"><el-button class="shopping-tool-button" text circle aria-label="編輯商品" @click="emit('edit', item)"><el-icon><Edit /></el-icon></el-button></el-tooltip><el-tooltip v-if="canEditTrip" content="刪除商品" placement="top"><el-button class="shopping-tool-button is-danger" text circle aria-label="刪除商品" @click="emit('remove', item)"><el-icon><Delete /></el-icon></el-button></el-tooltip></div></article></div></section></div>
    <div v-else class="detail-empty-state shopping-empty"><el-icon><Picture /></el-icon><div><strong>{{ items.length ? '沒有符合篩選條件的商品' : '還沒有購物項目' }}</strong><p>{{ items.length ? '調整篩選條件，或新增新的購物項目。' : '把想買的伴手禮、代購或共同採買商品先記下來。' }}</p></div><el-button v-if="canEditTrip" class="shopping-add-button" @click="emit('add')">新增第一個商品</el-button></div>
  </section>
</template>

<style scoped>
.trip-detail-card{border:1px solid #e1e8e3;border-radius:16px;background:#fff;box-shadow:0 8px 24px rgba(18,63,58,.06)}.shopping-panel{align-self:start;padding:24px}.detail-card-heading{display:flex;align-items:flex-start;justify-content:space-between;gap:14px;padding-bottom:17px;border-bottom:1px solid #e8eeea}.section-kicker{margin:0 0 4px;color:#d1826e;font-size:11px;font-weight:800;letter-spacing:1.4px}.detail-card-heading h2{margin:0;color:#163b37;font-size:20px;line-height:1.35}.detail-card-heading p:not(.section-kicker){margin:4px 0 0;color:#6b7d78;font-size:13px;line-height:1.5}.shopping-heading-actions{display:flex;flex-wrap:wrap;justify-content:flex-end;gap:8px}.shopping-add-button,.shopping-store-mode{display:inline-flex;gap:6px;min-height:40px;border-radius:10px;font-weight:700}.shopping-add-button{border:0;background:#123f3a;color:#fff}.shopping-add-button:hover,.shopping-add-button:focus-visible{background:#1d5a52;color:#fff}.shopping-store-mode{border-color:#c8ded4;background:#fff;color:#2f7d70}.shopping-store-mode:hover,.shopping-store-mode.is-active{border-color:#84b6a5;background:#eef5f0;color:#123f3a}.readonly-chip{display:inline-flex;align-items:center;min-height:32px;padding:0 10px;border-radius:999px;background:#eef5f0;color:#62766f;font-size:13px;font-weight:700}.shopping-summary{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:8px;margin-top:16px}.shopping-summary>div{display:grid;gap:2px;padding:10px 11px;border:1px solid #e2ebe5;border-radius:10px;background:#fbfcfa}.shopping-summary span{color:#71827c;font-size:12px}.shopping-summary strong{overflow:hidden;color:#173d37;font-size:14px;text-overflow:ellipsis;white-space:nowrap}.shopping-filters{display:flex;flex-wrap:wrap;gap:8px;margin-top:16px}.shopping-filters :deep(.el-select){width:145px}.shopping-group-button{min-height:36px;color:#2f7d70;font-weight:700}.shopping-groups{display:grid;gap:15px;margin-top:17px}.shopping-store-group{overflow:hidden;border:1px solid #e2ebe6;border-radius:12px;background:#fbfcfa}.shopping-store-heading{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:10px 13px;border-bottom:1px solid #e7eeea;background:#f1f7f3}.shopping-store-heading>div{display:flex;align-items:center;gap:6px;color:#1c5148}.shopping-store-heading strong{font-size:14px}.shopping-store-heading span{color:#668078;font-size:12px}.shopping-list{display:grid;gap:8px;padding:9px}.shopping-row{display:grid;grid-template-columns:58px minmax(0,1fr) minmax(82px,auto) auto;align-items:start;gap:11px;padding:10px;border:1px solid #e3ebe7;border-radius:10px;background:#fff;transition:border-color .16s,box-shadow .16s}.shopping-row:hover,.shopping-row:focus-within{border-color:#bed8cd;box-shadow:0 4px 12px rgba(18,63,58,.06)}.shopping-row.is-purchased{opacity:.72}.shopping-row.is-purchased .shopping-title strong{text-decoration:line-through}.shopping-row.is-high{border-left:3px solid #ff927c;padding-left:8px}.shopping-image{width:58px;height:58px;border-radius:9px;object-fit:cover}.shopping-image-placeholder{display:grid;place-items:center;background:#edf5f0;color:#4d917f;font-size:23px}.shopping-copy{min-width:0}.shopping-title{display:flex;flex-wrap:wrap;align-items:center;gap:5px}.shopping-title strong{overflow-wrap:anywhere;color:#244a43;font-size:15px;line-height:1.4}.shopping-status-badge,.shopping-priority-badge,.shopping-tags span{padding:2px 7px;border-radius:999px;font-size:11px;font-weight:700;white-space:nowrap}.shopping-status-badge.is-wishlist{background:#eef5f0;color:#48796d}.shopping-status-badge.is-planned{background:#e8f1f4;color:#3a7380}.shopping-status-badge.is-purchased{background:#e4f2eb;color:#267160}.shopping-status-badge.is-unavailable{background:#fff4d9;color:#926a21}.shopping-status-badge.is-cancelled{background:#f0f2f1;color:#7c8d87}.shopping-priority-badge.is-high{background:#fce9e7;color:#b64237}.shopping-priority-badge.is-medium{background:#fff4d9;color:#8a641c}.shopping-priority-badge.is-low{background:#eef2f0;color:#71827c}.shopping-tags,.shopping-meta,.shopping-note{display:flex;flex-wrap:wrap;gap:4px 8px;margin:4px 0 0;color:#71827c;font-size:12px;line-height:1.45}.shopping-tags span{background:#f0f5f2;color:#5b7770;font-weight:600}.shopping-meta span{display:inline-flex;align-items:center;gap:3px}.shopping-meta .el-icon{color:#4b907e;font-size:13px}.shopping-note{color:#84938d;overflow-wrap:anywhere}.shopping-price{display:grid;justify-items:end;gap:2px;padding-top:2px;color:#71827c;font-size:11px;text-align:right}.shopping-price strong{color:#173d37;font-size:14px;white-space:nowrap}.shopping-tools{display:flex;align-items:flex-start;gap:0}.shopping-tool-button{display:grid;width:36px!important;min-width:36px!important;height:36px!important;place-items:center;margin:0 -3px 0 0!important;padding:0!important;border-radius:8px;color:#638077;text-decoration:none}.shopping-tool-button:hover,.shopping-tool-button:focus-visible{background:#eef5f0;color:#236c59}.shopping-tool-button.is-purchase{color:#2f7d70;font-size:17px;font-weight:800}.shopping-tool-button.is-expense{color:#89641b;font-weight:800}.shopping-tool-button.is-danger{color:#c36358}.shopping-tool-button.is-danger:hover,.shopping-tool-button.is-danger:focus-visible{background:#fdf0ed;color:#b64237}.detail-empty-state{display:grid;place-items:center;gap:10px;padding:38px 16px;text-align:center;color:#6b7d78}.detail-empty-state>.el-icon{font-size:30px;color:#9db8ae}.detail-empty-state strong{color:#244a43;font-size:16px}.detail-empty-state p{margin:5px 0 8px;font-size:14px;line-height:1.55}@media(max-width:820px){.shopping-summary{grid-template-columns:repeat(3,minmax(0,1fr))}.shopping-row{grid-template-columns:54px minmax(0,1fr) auto}.shopping-price{grid-column:2;justify-items:start;padding:0;text-align:left}.shopping-tools{grid-column:3;grid-row:1/3;flex-direction:column;gap:0}.shopping-tool-button{margin:0!important}}@media(max-width:600px){.shopping-panel{padding:18px}.detail-card-heading{flex-direction:column}.shopping-heading-actions{width:100%;justify-content:stretch}.shopping-heading-actions .el-button{flex:1}.shopping-summary{grid-template-columns:repeat(2,minmax(0,1fr));gap:7px}.shopping-filters{display:grid;grid-template-columns:repeat(2,minmax(0,1fr))}.shopping-filters :deep(.el-select){width:100%}.shopping-group-button{grid-column:1/-1}.shopping-row{grid-template-columns:48px minmax(0,1fr) 40px;gap:9px;padding:9px}.shopping-image{width:48px;height:48px}.shopping-tools{grid-column:3;grid-row:1/4}.shopping-tool-button{width:40px!important;min-width:40px!important;height:40px!important}.shopping-price{grid-column:2}.shopping-store-heading{padding:9px 10px}.shopping-list{padding:7px}.shopping-store-mode{font-size:12px}}@media(max-width:390px){.shopping-panel{padding:16px}.shopping-filters{grid-template-columns:1fr}.shopping-summary{grid-template-columns:repeat(2,minmax(0,1fr))}.shopping-summary>div:last-child{grid-column:1/-1}.shopping-row{padding-left:7px}.shopping-title strong{font-size:14px}}
</style>
